export const PERSONA1_TEMPLATES: Record<"day0" | "day3" | "day7" | "day14", string> = {
  "day0": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Your HVAC sizing — and the words that'll save you on quotes</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#ffffff;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#27272a;\">\n  <div style=\"max-width:600px;margin:0 auto;padding:32px 20px;\">\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">Hey there,</p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      You just calculated the heating and cooling needs of your {{ home.sqft | comma }} sqft home in {{ location.city }}, {{ location.state }}. Three numbers came out the other side:\n    </p>\n\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li><strong>Cooling:</strong> {{ home.cooling_btu | comma }} BTU/hr</li>\n      <li><strong>Heating:</strong> {{ home.heating_btu | comma }} BTU/hr</li>\n      <li><strong>System size:</strong> {{ home.tonnage }} tons</li>\n    </ul>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      These three numbers are the most useful sentences you can say to an HVAC contractor. Most homeowners walk into the first quote conversation with no idea what size they need. You won't.\n    </p>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">What the lingo actually means</h2>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Nobody is born knowing this. Quick translation:\n    </p>\n\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\">\n        <strong>BTU</strong> (British Thermal Unit) is just a unit of heat &mdash; like calories for energy. Bigger home, harsher weather, thinner insulation = more BTUs your system has to move. The bigger the load, the bigger the equipment.\n      </li>\n      <li style=\"margin-bottom:10px;\">\n        <strong>Tonnage</strong> has nothing to do with weight. In HVAC, 1 ton = 12,000 BTU/hr of cooling. Your {{ home.tonnage }}-ton system is rated to move {{ home.tonnage | times: 12000 | comma }} BTU/hr of heat out of your home on a hot day. Why \"tons\"? Holdover from when buildings were cooled with literal blocks of ice &mdash; 1 ton was the cooling power of a ton of ice melting over a day. The term stuck.\n      </li>\n      <li>\n        <strong>Why we give you both heating AND cooling numbers:</strong> some contractors only size for one. If they pick a system based on summer cooling alone, you might end up with heating that struggles in winter. The system they propose should comfortably handle both numbers above.\n      </li>\n    </ul>\n\n    {% assign is_cold = false %}\n    {% assign is_hot = false %}\n    {% assign is_temperate = false %}\n    {% if location.climate_region == \"Cold\" %}{% assign is_cold = true %}{% endif %}\n    {% if location.climate_region == \"Hot\" %}{% assign is_hot = true %}{% endif %}\n    {% if location.climate_region == \"Warm\" or location.climate_region == \"Mixed\" or location.climate_region == \"Cool\" %}{% assign is_temperate = true %}{% endif %}\n\n    {% if is_cold %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 14px 0;\">\n      Your climate matters too. {{ location.city }} sits in a <strong>cold climate</strong> &mdash; the U.S. building-energy code (called the <strong>IECC</strong>, International Energy Conservation Code) splits the country into climate zones, and you're in Zone {{ location.iecc_zone }}. Your <strong>design heating temperature</strong> is around {{ location.design_temp_low }}&deg;F, which is roughly the coldest you can reasonably expect on a winter day. So heating, not cooling, is your main load.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 14px 0;\">\n      That matters because cold-climate homes are exactly where contractors tend to default to gas furnaces and dismiss heat pumps. A <strong>heat pump</strong> is a piece of equipment that does both heating and cooling with no fuel burning &mdash; instead of generating heat, it moves heat (it pulls heat from outside air, even cold outside air, and brings it inside). Modern ones work fine well below 0&deg;F, but the industry hasn't fully caught up with that fact.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      If you're open to a heat pump, here's the benchmark to know: ask each contractor for a <strong>cold-climate heat pump</strong> with an <strong>HSPF2 rating of 9 or higher</strong>. HSPF2 (it stands for Heating Seasonal Performance Factor &mdash; the \"2\" just means the modern testing standard) is basically the heat-pump version of MPG: higher = more heat per unit of electricity. As a benchmark: 7 is budget, 8 is solid, 9+ is high-efficiency. We'll come back to this on Day 7 because HSPF2 9+ also unlocks a federal tax credit worth up to $2,000.\n    </p>\n    {% endif %}\n\n    {% if is_hot %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 14px 0;\">\n      Your climate matters too. {{ location.city }} sits in a <strong>hot climate</strong> &mdash; the U.S. building-energy code (called the <strong>IECC</strong>, International Energy Conservation Code) splits the country into climate zones, and you're in Zone {{ location.iecc_zone }}. Your <strong>design cooling temperature</strong> is around {{ location.design_temp_high }}&deg;F, which is roughly the hottest you can reasonably expect on a summer day. So cooling, not heating, is your main load.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      The thing nobody mentions for hot climates: <strong>humidity</strong> is half the comfort equation. A system that just lowers the temperature without removing moisture leaves your home cool and clammy. The industry term for \"how much humidity does this thing pull out of the air\" is <strong>latent capacity</strong>. Ask each contractor what their proposed system's latent capacity is &mdash; most won't volunteer the number, but a sharp installer can pull it from the equipment spec sheet without breaking a sweat.\n    </p>\n    {% endif %}\n\n    {% if is_temperate %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 14px 0;\">\n      Your climate matters too. {{ location.city }} sits in a {{ location.climate_region | downcase }} climate &mdash; the U.S. building-energy code (called the <strong>IECC</strong>, International Energy Conservation Code) splits the country into climate zones, and you're in Zone {{ location.iecc_zone }}. Both heating and cooling matter in your area, which is why a <strong>heat pump</strong> tends to be the cleanest answer for homes like yours.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      A heat pump is a piece of equipment that does both heating and cooling with no fuel burning &mdash; instead of generating heat, it moves heat. One outdoor unit, both jobs. Worth asking each contractor whether they recommend a heat pump or a traditional AC + furnace combo, and why &mdash; the answer reveals how they think.\n    </p>\n    {% endif %}\n\n    {% if home.occupants >= 5 %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      One thing specific to you: with {{ home.occupants }} people in the house, your humidity load is a bit higher than the calculator's defaults. People generate heat and moisture just by existing &mdash; that's not a flaw in the calc, just a known correction. Mention occupant count when you talk to contractors; a thorough installer will adjust their math for it.\n    </p>\n    {% endif %}\n\n    {% if home.insulation == \"Worse than avg\" or home.insulation == \"Bad\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Worth flagging: you marked your insulation as {{ home.insulation | downcase }}. That changes the math. If you spend $2-3K upgrading insulation <em>before</em> the HVAC install, your new system can be a smaller (cheaper) size, run less often, and keep you more comfortable. Don't let HVAC contractors skip the insulation conversation just because you came to them for HVAC. (HVAC people call the outer shell of your home &mdash; walls, attic, windows, doors &mdash; the <strong>envelope</strong>. Anything that separates inside from outside.)\n    </p>\n    {% endif %}\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">What's coming over the next two weeks</h2>\n\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 20px 24px;padding:0;\">\n      <li><strong>Day 3</strong> &mdash; the 10 things every HVAC quote should include, written so you can spot a sketchy bid the moment it lands.</li>\n      <li><strong>Day 7</strong> &mdash; a federal tax credit worth up to $2,000 most homeowners don't claim because nobody told them.</li>\n      <li><strong>Day 14</strong> &mdash; when you're ready, the fastest way to get 3 quotes side-by-side.</li>\n    </ul>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 8px 0;\">\n      When you're ready to start getting quotes:\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 28px 0;\">\n      <a href=\"{{ cta_url }}\" style=\"color:#FF6B2B;font-weight:600;text-decoration:underline;\">Get matched with local pros via Angi &rarr;</a>\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 4px 0;\">&mdash; The NailTheQuote team</p>\n\n        <hr style=\"border:none;border-top:1px solid #e4e4e7;margin:32px 0 16px 0;\">\n    <p style=\"font-size:12px;color:#a1a1aa;line-height:1.5;margin:0 0 6px 0;\">\n      You're receiving this because you used the <a href=\"https://nailthequote.com/hvac/load-calculator/\" style=\"color:#a1a1aa;\">Load Calculator</a> on NailTheQuote.com. We send up to 4 emails over 2 weeks, then stop.\n    </p>\n    <p style=\"font-size:11px;color:#a1a1aa;margin:0;\">\n      NailTheQuote.com &middot; Free tools for homeowners and contractors<br>\n      {% raw %}<a href=\"{{{unsubscribe_url}}}\" style=\"color:#a1a1aa;\">Unsubscribe</a>{% endraw %}\n    </p>\n\n\n  </div>\n</body>\n</html>\n",
  "day3": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>The 10 things every HVAC quote should include</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#ffffff;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#27272a;\">\n  <div style=\"max-width:600px;margin:0 auto;padding:32px 20px;\">\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Three days ago you calculated your home's load &mdash; {{ home.cooling_btu | comma }} BTU cooling, {{ home.tonnage }} tons. Knowing the size is step one. Step two is reading quotes well enough to spot a real bid versus a number on a napkin.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      Below is the 10-item checklist. Print it, screenshot it, forward it to whoever's deciding with you. The pattern matters more than any single line: a quote missing 3 or more items is telling you something about how the contractor operates.\n    </p>\n\n    <!-- 1. Permit -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">1. A permit, pulled by the contractor.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      You probably didn't know an HVAC install requires a building permit. It does &mdash; almost everywhere in the U.S. The <strong>permit</strong> is your local building department's way of saying \"we'll send an inspector to verify this was installed correctly.\" Why the contractor (not you) should pull it: a licensed contractor pulls the permit under <em>their</em> license, which makes them legally responsible for passing inspection.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      A real quote will list the permit fee (typically $50-$500) as a line item. If it's not there, ask why &mdash; and how the inspection is being handled.\n    </p>\n\n    <!-- 2. Equipment + AHRI -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">2. Specific make, model, and AHRI certificate number.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Not just \"3-ton Carrier system.\" That's a vibe, not a quote. A real bid names exactly which <strong>outdoor unit</strong> (the box outside your house, often called the \"condenser\") and which <strong>indoor unit</strong> (the cabinet usually in your basement, attic, or closet &mdash; sometimes called the \"air handler\") you're getting, with their model numbers AND an <strong>AHRI certificate number</strong>.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Plain-English context: HVAC manufacturers sell components separately &mdash; the outdoor unit and the indoor unit are two different boxes that get installed together. <strong>AHRI</strong> is the Air-Conditioning, Heating, and Refrigeration Institute, an independent industry lab. AHRI tests pairs of components together and certifies their actual real-world efficiency.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      \"AHRI-matched\" means the indoor and outdoor units have been tested as a pair and confirmed to work at their advertised efficiency. Mismatched pairs (a contractor pairing a new outdoor unit with your old indoor coil, for instance, to save money) can be 15-20% less efficient than the box says &mdash; and you only find out when your electricity bills come in higher than expected. The AHRI certificate is a one-page PDF available at ahridirectory.org. A reputable contractor lists the certificate number on the quote, or can email it within an hour.\n    </p>\n\n    <!-- 3. Refrigerant -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">3. The refrigerant type, and where the old refrigerant is going.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      The fluid inside an AC or heat pump is called <strong>refrigerant</strong>. It's what carries heat in or out of your home &mdash; different from water-based heating systems. Refrigerant is regulated because it can damage the atmosphere if released, so handling it requires a federal certification called <strong>EPA 608</strong>. Any technician who touches refrigerant is supposed to have it.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>Two specific things to ask:</strong>\n    </p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:8px;\"><strong>Which refrigerant does the new system use?</strong> R-410A (the old standard) is being phased out under U.S. environmental rules. The replacements are R-32 and R-454B. Quotes still using R-410A on new installs are either selling old stock (cheaper for the contractor, harder for you to repair in 5+ years when it's no longer manufactured) or behind on training.</li>\n      <li><strong>Who's reclaiming the refrigerant from your old system?</strong> It can't legally be vented to the atmosphere. Should be itemized.</li>\n    </ul>\n\n    <!-- 4. Ductwork -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">4. Ductwork &mdash; what's included, what's being ignored.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Quick orientation: <strong>ducts</strong> are the metal or insulated-fabric tubes that carry heated or cooled air from your HVAC system to each room. They run inside walls, ceilings, attics, and basements &mdash; you usually only see them as the slotted vents on your floors or ceilings (those are called <strong>registers</strong>). If you have central heat or central AC, you have ducts.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      A lot of post-install comfort complaints &mdash; rooms that don't get cool enough, weird airflow noises, dust everywhere &mdash; trace back to ductwork rather than the new equipment. So a quote silent on ductwork is hiding either an upsell (\"we'll find issues during install\") or a problem they don't want to fix yet.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      A real quote should mention: any new duct runs needed, any duct sealing or insulation, any repairs to existing ducts.\n    </p>\n\n    {% if home.sqft >= 3000 %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;background-color:#fff7ed;border-left:3px solid #FF6B2B;padding:12px 16px;\">\n      At your home size ({{ home.sqft | comma }} sqft), ductwork is a much bigger conversation. Ask each contractor whether your existing ducts can handle a {{ home.tonnage }}-ton system. The industry rule of thumb is <strong>400 cubic feet of air per minute, per ton of cooling</strong>. So your ducts need to move roughly {{ home.tonnage | times: 400 | comma }} cubic feet of air per minute when the system runs at full capacity. If they can't, the best equipment in the world will choke. The contractor should be able to explain this in plain language; if they can't, find one who can.\n    </p>\n    {% endif %}\n\n    <!-- 5. Warranty -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">5. Warranty terms &mdash; both parts AND labor, separately.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">There are two warranties on every HVAC install, and they cover different things:</p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 12px 24px;padding:0;\">\n      <li style=\"margin-bottom:8px;\"><strong>Parts warranty</strong> comes from the manufacturer. Usually 10 years on major components if you register the unit. This covers the equipment itself if something breaks.</li>\n      <li><strong>Labor warranty</strong> comes from the contractor. Usually 1-2 years. This covers the contractor's cost to install the replacement part if something fails.</li>\n    </ul>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Why both matter: if a $400 part fails and the manufacturer covers it but you have no labor warranty, you're paying $1,500+ in labor to install the free part. A contractor with no labor warranty is telling you they don't trust their own install.\n    </p>\n\n    <!-- 6. Commissioning -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">6. Commissioning &mdash; the magic word.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>Commissioning</strong> is the post-install testing that confirms the system actually works at the rated efficiency. After they install it, the technician should:\n    </p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 12px 24px;padding:0;\">\n      <li>Measure airflow at every register</li>\n      <li>Check that the refrigerant charge is exactly right (not too much, not too little &mdash; both cause problems)</li>\n      <li>Measure the temperature difference between the air going in and coming out</li>\n      <li>Hand you a written report with all the numbers</li>\n    </ul>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Most contractors skip this step entirely. The ones who don't are the ones to hire. If a quote doesn't mention commissioning, ask the contractor specifically: \"Will you do a commissioning report, and what does it cost extra?\" Their answer tells you which kind of contractor they are.\n    </p>\n\n    <!-- 7. Disposal -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">7. Old-system disposal.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Hauling away the old equipment, reclaiming the old refrigerant, all of it. Should be a line item, not an afterthought. A contractor who leaves your old AC sitting in the side yard \"for you to handle\" is a contractor who's also probably cutting other corners.\n    </p>\n\n    <!-- 8. Electrical -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">8. Electrical work.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      A new HVAC system needs electrical service to run, and a real quote should call out the specific electrical pieces. The basics:\n    </p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 12px 24px;padding:0;\">\n      <li style=\"margin-bottom:6px;\"><strong>Disconnect</strong> &mdash; a small outdoor switch box mounted on the wall next to the unit. Lets a technician cut power to the system without going to your main panel.</li>\n      <li style=\"margin-bottom:6px;\"><strong>Breaker</strong> &mdash; a new switch in your home's electrical panel, sized for the new system's electrical load.</li>\n      <li><strong>Whip</strong> &mdash; a short flexible cable that connects the disconnect to the unit itself.</li>\n    </ul>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      If your home's electrical panel is old (common in homes built before 1990) and needs upgrading to handle the new system, that's a separate licensed-electrician job &mdash; and a separate line item on the quote. Don't let an HVAC contractor hide a $2,000 panel upgrade inside the HVAC bid; it should be itemized clearly.\n    </p>\n\n    <!-- 9. Zoning -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">9. Zoning, if applicable.</h3>\n    {% if home.sqft >= 2500 %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      For a {{ home.sqft | comma }} sqft home, ask about <strong>zoning</strong> explicitly. Zoning means the home is split into independently-controlled regions, each with its own thermostat. Motorized <strong>dampers</strong> (basically flaps inside the ducts) open and close to direct airflow where it's wanted. A 2- or 3-zone setup typically adds $1,000-$3,000 up front but pays back in comfort + bills, especially in multi-story homes (heat rises, so the upstairs is always too hot in summer without zoning).\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      If a contractor doesn't bring up zoning for a home your size, they're either not thinking carefully or they're optimizing for \"cheapest bid\" over \"best system.\"\n    </p>\n    {% else %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Probably not relevant for your home size, but worth knowing the term: <strong>zoning</strong> means having multiple thermostats and <strong>dampers</strong> (motorized flaps in the ducts) that let you cool different rooms independently. Comes up more often in larger or multi-story homes.\n    </p>\n    {% endif %}\n\n    <!-- 10. Labor breakdown -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">10. Labor breakdown, separated from equipment.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      Total bid should split into equipment, materials, labor, permit, disposal. If it's one lump sum, you can't compare quotes meaningfully &mdash; and the contractor knows it. Ask for the breakdown.\n    </p>\n\n    <!-- Climate-specific watch-out -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:32px 0 8px 0;\">One climate-specific watch-out:</h3>\n\n    {% if location.climate_region == \"Cold\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      In zone {{ location.iecc_zone }} ({{ location.state }}), ask whether the system is sized for the <strong>design heating temperature</strong> ({{ location.design_temp_low }}&deg;F &mdash; the coldest you can reasonably expect on a winter day) or for a milder average winter day. Some contractors size for the average to win on bid price; you then have an under-sized system three weeks every winter. Real bids reference design conditions explicitly.\n    </p>\n    {% endif %}\n\n    {% if location.climate_region == \"Hot\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      In zone {{ location.iecc_zone }} ({{ location.state }}), ask the contractor what their <strong>Manual J calculation</strong> says about your latent (humidity) load. Manual J is the industry-standard load calc &mdash; the same kind of math the calculator on our site did, but more thorough. If a contractor doesn't run a Manual J, or hand-waves latent capacity, that's a contractor who oversizes systems and produces clammy, uncomfortable homes. The bid should reference Manual J as the basis.\n    </p>\n    {% endif %}\n\n    {% if location.climate_region == \"Warm\" or location.climate_region == \"Mixed\" or location.climate_region == \"Cool\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      In zone {{ location.iecc_zone }}, the system has to perform across a wide temperature range. Ask specifically how their proposed equipment handles design heating ({{ location.design_temp_low }}&deg;F) AND design cooling ({{ location.design_temp_high }}&deg;F). A bid addressing only one is half a bid.\n    </p>\n    {% endif %}\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      <strong>The use:</strong> when Angi sets up your 3 quotes, run each one through this list. The one that scores highest isn't always the cheapest &mdash; but it's almost always the one you'll be glad you picked.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 28px 0;\">\n      <a href=\"{{ cta_url }}\" style=\"color:#FF6B2B;font-weight:600;text-decoration:underline;\">Get 3 quotes you can actually compare &rarr;</a>\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 4px 0;\">&mdash; NailTheQuote</p>\n\n        <hr style=\"border:none;border-top:1px solid #e4e4e7;margin:32px 0 16px 0;\">\n    <p style=\"font-size:12px;color:#a1a1aa;line-height:1.5;margin:0 0 6px 0;\">\n      You're receiving this because you used the <a href=\"https://nailthequote.com/hvac/load-calculator/\" style=\"color:#a1a1aa;\">Load Calculator</a> on NailTheQuote.com. We send up to 4 emails over 2 weeks, then stop.\n    </p>\n    <p style=\"font-size:11px;color:#a1a1aa;margin:0;\">\n      NailTheQuote.com &middot; Free tools for homeowners and contractors<br>\n      {% raw %}<a href=\"{{{unsubscribe_url}}}\" style=\"color:#a1a1aa;\">Unsubscribe</a>{% endraw %}\n    </p>\n\n\n  </div>\n</body>\n</html>\n",
  "day7": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>A federal tax credit worth up to $2,000 most homeowners don't claim</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#ffffff;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#27272a;\">\n  <div style=\"max-width:600px;margin:0 auto;padding:32px 20px;\">\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      A week ago you calculated a {{ home.tonnage }}-ton system for your {{ home.sqft | comma }} sqft {{ location.city }} home. Today's email is about turning that into actual money off, via a federal tax credit most homeowners don't know to ask for.\n    </p>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">Where this credit comes from</h2>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      In 2022, Congress passed the <strong>Inflation Reduction Act</strong> (IRA) &mdash; a law that included a long list of incentives for energy-efficient home upgrades. <strong>Section 25C</strong> of the IRA covers HVAC. Specifically:\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;background-color:#fff7ed;border-left:3px solid #FF6B2B;padding:12px 16px;\">\n      If you install a qualifying heat pump in 2026, you get <strong>30% of project cost back as a federal tax credit, capped at $2,000</strong>.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\"><strong>A few important details:</strong></p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\">This is a <strong>tax credit</strong>, not a tax deduction. Big difference. A <em>deduction</em> lowers the income you pay tax on (so a $2,000 deduction at a 24% tax rate saves you $480). A <em>credit</em> lowers your tax bill directly, dollar for dollar &mdash; $2,000 credit = $2,000 less owed to the IRS, or $2,000 more in your refund.</li>\n      <li style=\"margin-bottom:10px;\">The credit applies <strong>only to heat pumps</strong> &mdash; not to traditional central air conditioners or gas furnaces. (Those qualify for separate, smaller credits under the same law.) If you weren't already considering a heat pump, this credit might tip the math.</li>\n      <li>The total annual cap on all 25C improvements (heat pumps, water heaters, insulation, windows, etc.) is $3,200, with the $2,000 heat-pump cap nested inside it.</li>\n    </ul>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">Quick refresher on what a heat pump is</h2>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      A <strong>heat pump</strong> is a single piece of HVAC equipment that handles both heating and cooling. Mechanically it works the same way as an air conditioner &mdash; moving heat from one place to another &mdash; but it can run in either direction. In summer it pulls heat out of your home (cooling). In winter it pulls heat from outside air (yes, even cold outside air still has heat in it) and brings that heat indoors. One outdoor unit, no separate furnace, no fuel burning. Modern ones work down to about -10&deg;F without any backup heat needed.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">Three flavors all qualify for 25C:</p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 24px 24px;padding:0;\">\n      <li style=\"margin-bottom:8px;\"><strong>Ducted air-source heat pump</strong> &mdash; uses your existing ductwork, like a traditional central AC. Most common for whole-home installs.</li>\n      <li style=\"margin-bottom:8px;\"><strong>Ductless mini-split</strong> &mdash; small wall-mounted indoor units that don't need ducts. Common for additions or homes that never had ductwork.</li>\n      <li><strong>Geothermal heat pump</strong> &mdash; pulls heat from the ground rather than the air. More expensive up front; covered under a different (larger) IRA section, but the same idea.</li>\n    </ul>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">The plain-English rules for claiming the 25C credit</h2>\n\n    <h3 style=\"font-size:16px;color:#18181b;margin:20px 0 8px 0;\">1. The equipment has to meet efficiency thresholds.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Specifically, for 2026 installs, the IRS requires equipment that meets the <strong>CEE highest tier</strong> (excluding any \"advanced\" tier). <strong>CEE</strong> stands for Consortium for Energy Efficiency &mdash; an industry nonprofit that publishes efficiency tiers, which the IRS adopted as the goalposts for who qualifies. In practice: high-efficiency equipment, but not the absolute top of the line. Your contractor should know which models qualify; if they can't tell you, that's a red flag.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>The numbers your contractor will reference (here's what they all mean):</strong>\n    </p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\"><strong>SEER2</strong> = Seasonal Energy Efficiency Ratio (cooling). It's a measure of how much cooling you get per unit of electricity, averaged across a typical cooling season. Higher = more efficient. As benchmarks: SEER2 13-14 is budget; 16-18 is mid-range; 20+ is high-efficiency.</li>\n      <li style=\"margin-bottom:10px;\"><strong>HSPF2</strong> = Heating Seasonal Performance Factor. Same idea, but for heating. Higher = more heat per unit of electricity. Benchmarks: 7 is budget; 8-9 is solid; 9+ is high-efficiency, and it's roughly the threshold the 25C credit requires for qualifying heat pumps.</li>\n      <li style=\"margin-bottom:10px;\"><strong>EER2</strong> = Energy Efficiency Ratio at peak conditions (the hottest hour of the hottest day). Higher = the system holds up under stress, not just on average days.</li>\n      <li><strong>Why \"2\"?</strong> SEER2 / HSPF2 / EER2 are the same metrics measured under a newer (post-2023) test standard. Older SEER / HSPF numbers (without the 2) are not directly comparable &mdash; for rough conversion, an old \"16 SEER\" rating &asymp; \"15 SEER2\" today.</li>\n    </ul>\n\n    <h3 style=\"font-size:16px;color:#18181b;margin:20px 0 8px 0;\">2. You need a manufacturer's certification statement.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Every qualifying model has a <strong>manufacturer's certification statement</strong> &mdash; a one-page PDF from the manufacturer that explicitly says \"this specific model meets the 25C efficiency thresholds for tax year 2026.\" That's the document you (or your tax preparer) reference when filing.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Ask the contractor for this PDF before you sign the contract</strong>, not after. A reputable contractor can produce it in five minutes &mdash; they get it routinely from the manufacturer or distributor. A contractor who can't or won't is either (a) not familiar with 25C, or (b) selling you a model that doesn't qualify and hoping you won't notice. Either way, that's the contractor you don't hire.\n    </p>\n\n    <h3 style=\"font-size:16px;color:#18181b;margin:20px 0 8px 0;\">3. You file IRS Form 5695 with your federal tax return.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      The credit is claimed on <strong>Form 5695, line 22a</strong>. It's one number, on one line. The hard part is gathering the paperwork (the manufacturer's certification statement, the contractor's itemized invoice). The actual filing is the easiest part.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      If you use TurboTax or H&amp;R Block, look for the \"Energy-Saving Home Improvements\" section &mdash; they'll prompt you for everything. If you use a CPA, hand them the certification statement and the invoice; they'll know exactly what to do.\n    </p>\n\n    <h3 style=\"font-size:16px;color:#18181b;margin:20px 0 8px 0;\">4. The credit stacks with state and utility rebates.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      This part matters: the federal $2,000 doesn't get reduced by anything you receive at the state or utility level. So if your utility offers a $500 rebate AND your state offers a $1,500 rebate, you can stack them: $500 (utility) + $1,500 (state) + up to $2,000 (federal) = $4,000 off the install.\n    </p>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">For your situation specifically</h2>\n\n    {% if location.climate_region == \"Cold\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      You're in a cold climate (zone {{ location.iecc_zone }}, design heating temperature around {{ location.design_temp_low }}&deg;F), where the heat pump credit is most valuable. Modern cold-climate heat pumps clear the HSPF2 9 threshold without needing exotic equipment. If a contractor pushes back with \"heat pumps don't work well in cold weather\" &mdash; that hasn't been true for a decade. Ask specifically: \"Do you install cold-climate heat pumps? Which models?\" Their answer reveals whether they're current.\n    </p>\n    {% endif %}\n\n    {% if location.climate_region == \"Hot\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      You're in a hot climate, where almost any modern heat pump clears the SEER2 and EER2 thresholds. The bigger question is whether the contractor recommends a heat pump at all, or defaults to a traditional central AC + gas furnace combo. The traditional combo is cheaper up front, but central AC alone <em>doesn't</em> qualify for the $2,000 credit &mdash; only heat pumps do. If you're open to a heat pump, push for that option specifically.\n    </p>\n    {% endif %}\n\n    {% if location.climate_region == \"Warm\" or location.climate_region == \"Mixed\" or location.climate_region == \"Cool\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      A heat pump is a no-brainer for your zone (IECC {{ location.iecc_zone }}), and the SEER2 / HSPF2 thresholds are easy to meet. The watch-out: some contractors quote a qualifying outdoor unit but pair it with an older indoor coil, dropping the system's overall rating below the threshold and voiding the credit. Insist on AHRI-matched components (see Day 3, item 2) &mdash; and verify the certification statement is for the matched pair, not the outdoor unit by itself.\n    </p>\n    {% endif %}\n\n    {% if home.tonnage <= 2 %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Your {{ home.tonnage }}-ton load is on the smaller side, which means ductless mini-splits are very competitive options for you. Mini-splits qualify for the same $2,000 cap as ducted heat pumps, with their own (slightly higher) efficiency thresholds. Worth comparing both ducted and mini-split bids if your home doesn't already have ductwork.\n    </p>\n    {% endif %}\n\n    {% if home.tonnage > 5 %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Your {{ home.tonnage }}-ton load is on the larger end. Qualifying heat pumps exist at this size, but the market thins out &mdash; your contractor may propose splitting your home into two systems (two outdoor units, each handling part of the home). Each separate heat pump can qualify independently for the $2,000 credit if installed in different tax years. Worth asking about.\n    </p>\n    {% endif %}\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">The state-level rebate stack</h2>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      {{ location.state }} runs its own rebate programs alongside the federal credit. The U.S. Department of Energy rolled out two big programs in 2024 &mdash; <strong>HEEHRA</strong> (the High-Efficiency Electric Home Rebate Act, which gives upfront rebates rather than tax credits) and <strong>HOMES</strong> (the HOMES Rebate Program, which gives rebates based on actual energy savings). Both are funded by the IRA and administered state-by-state, so the launch date varies. Some states are live; others aren't yet.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      For up-to-date {{ location.state }} programs, check <strong>DSIRE</strong> &mdash; the Database of State Incentives for Renewables &amp; Efficiency, run by NC State University. DSIRE is the canonical, free, public list of every federal/state/utility incentive in the U.S.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      Direct link for {{ location.state }}: <a href=\"{{ rebate_lookup_url }}\" style=\"color:#FF6B2B;text-decoration:underline;\">{{ rebate_lookup_url }}</a>\n    </p>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">One specific contractor competence test</h2>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      When you're talking to contractors, this question separates the ones who file 25C regularly from the ones who don't:\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;font-style:italic;border-left:3px solid #e4e4e7;padding-left:16px;color:#3f3f46;\">\n      \"Is this equipment 25C-eligible, and will you provide the manufacturer's certification statement?\"\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 28px 0;\">\n      A contractor who says \"yes, here's the certification &mdash; and we can walk you through Form 5695\" files this credit regularly. A contractor who hesitates, dodges, or says \"talk to your CPA\" hasn't done it before &mdash; and you'd be the guinea pig. Note who answers cleanly. That's almost always the contractor you want.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 28px 0;\">\n      <a href=\"{{ cta_url }}\" style=\"color:#FF6B2B;font-weight:600;text-decoration:underline;\">Angi can connect you with pros experienced filing 25C &rarr;</a>\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 4px 0;\">&mdash; NailTheQuote</p>\n    <p style=\"font-size:14px;line-height:1.65;margin:0 0 16px 0;color:#71717a;font-style:italic;\">\n      P.S. The $2,000 cap resets every year. So if you're staging a multi-system project &mdash; say, a heat pump this year, a heat-pump water heater next year &mdash; you can claim 25C in both tax years.\n    </p>\n\n        <hr style=\"border:none;border-top:1px solid #e4e4e7;margin:32px 0 16px 0;\">\n    <p style=\"font-size:12px;color:#a1a1aa;line-height:1.5;margin:0 0 6px 0;\">\n      You're receiving this because you used the <a href=\"https://nailthequote.com/hvac/load-calculator/\" style=\"color:#a1a1aa;\">Load Calculator</a> on NailTheQuote.com. We send up to 4 emails over 2 weeks, then stop.\n    </p>\n    <p style=\"font-size:11px;color:#a1a1aa;margin:0;\">\n      NailTheQuote.com &middot; Free tools for homeowners and contractors<br>\n      {% raw %}<a href=\"{{{unsubscribe_url}}}\" style=\"color:#a1a1aa;\">Unsubscribe</a>{% endraw %}\n    </p>\n\n\n  </div>\n</body>\n</html>\n",
  "day14": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Two weeks in. Here's the 3-quote ask.</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#ffffff;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#27272a;\">\n  <div style=\"max-width:600px;margin:0 auto;padding:32px 20px;\">\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Two weeks ago you calculated a {{ home.tonnage }}-ton system for your {{ home.sqft | comma }} sqft home in {{ location.city }}, {{ location.state }}. Cooling: {{ home.cooling_btu | comma }} BTU. Heating: {{ home.heating_btu | comma }} BTU. Climate zone: IECC {{ location.iecc_zone }}.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">You've now got:</p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li><strong>Day 0</strong> &mdash; your sizing numbers and the vocabulary to use them.</li>\n      <li><strong>Day 3</strong> &mdash; the 10-item checklist for spotting a real quote vs. a sketchy one.</li>\n      <li><strong>Day 7</strong> &mdash; the 25C tax-credit framework and the contractor competence test.</li>\n    </ul>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      The only thing left is getting actual bids in front of you. The shortest path: 3 quotes from local licensed contractors, side-by-side, scored against the Day 3 checklist.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Why 3 specifically?</strong> One quote is a vibe. Two is a coin flip. Three is a real comparison &mdash; enough to spot which contractor is being thorough, which is cutting corners, and which is overcharging.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      Angi handles the matching: describe the project once, three vetted local contractors reach out within 24 hours. No phoning around to schedule 5 separate consultations from scratch.\n    </p>\n\n    <div style=\"margin:0 0 24px 0;text-align:center;\">\n      <a href=\"{{ cta_url }}\" style=\"display:inline-block;background:#FF6B2B;color:#ffffff;font-size:15px;font-weight:600;text-decoration:none;padding:14px 28px;border-radius:8px;\">\n        Get 3 free quotes from local HVAC pros &rarr;\n      </a>\n    </div>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      That's the email. Use what you've learned. Pick the quote that scores highest on the checklist, not lowest on price. And remember the 25C paperwork &mdash; the contractor should be willing to walk you through it, or at minimum hand you the manufacturer's certification statement before you sign.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">Good luck with the install.</p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 4px 0;\">&mdash; NailTheQuote</p>\n\n        <hr style=\"border:none;border-top:1px solid #e4e4e7;margin:32px 0 16px 0;\">\n    <p style=\"font-size:12px;color:#a1a1aa;line-height:1.5;margin:0 0 6px 0;\">\n      You're receiving this because you used the <a href=\"https://nailthequote.com/hvac/load-calculator/\" style=\"color:#a1a1aa;\">Load Calculator</a> on NailTheQuote.com. We send up to 4 emails over 2 weeks, then stop.\n    </p>\n    <p style=\"font-size:11px;color:#a1a1aa;margin:0;\">\n      NailTheQuote.com &middot; Free tools for homeowners and contractors<br>\n      {% raw %}<a href=\"{{{unsubscribe_url}}}\" style=\"color:#a1a1aa;\">Unsubscribe</a>{% endraw %}\n    </p>\n\n\n  </div>\n</body>\n</html>\n",
};

