export const PERSONA2_TEMPLATES: Record<"day0" | "day3" | "day10", string> = {
  "day0": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Score your HVAC quotes against this 10-item checklist</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#ffffff;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#27272a;\">\n  <div style=\"max-width:600px;margin:0 auto;padding:32px 20px;\">\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">Hey there,</p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      You told us you already have HVAC estimates in hand. Good &mdash; comparing quotes is the single biggest thing a homeowner can do to avoid getting taken on this kind of project. The trick is knowing what to compare. Most people compare on the bottom-line price, which is the dimension contractors are best at gaming.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Before anything else, here's what we calculated for your {{ home.sqft | comma }} sqft home in {{ location.city }}, {{ location.state }}:\n    </p>\n\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li><strong>Cooling:</strong> {{ home.cooling_btu | comma }} BTU/hr</li>\n      <li><strong>Heating:</strong> {{ home.heating_btu | comma }} BTU/hr</li>\n      <li><strong>System size:</strong> {{ home.tonnage }} tons</li>\n    </ul>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      First check on every quote you have: does the system being proposed match this size? You should see &ldquo;{{ home.tonnage }} tons&rdquo; or &ldquo;{{ home.cooling_btu | comma }} BTU/hr&rdquo; somewhere on the proposal. (1 ton = 12,000 BTU/hr of cooling capacity. The two numbers are just different units for the same thing.) If a contractor proposes something materially smaller or bigger than this without explaining why, that's the first conversation to have.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      Underbidding on system size is the easiest way for a contractor to win on price &mdash; and the easiest thing to &ldquo;fix&rdquo; mid-install (&ldquo;turns out you actually need a bigger unit, that'll be another $1,500&rdquo;). If two of your quotes propose the same size and one proposes smaller, the cheap-looking quote may not stay cheap.\n    </p>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">Now the checklist.</h2>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      Below are the 10 items every HVAC quote should already include. Score each of yours: &check; if it's clearly there, &times; if it isn't or is vague. A quote missing 3+ items is telling you something about how that contractor operates. Day 3 covers what to do about it.\n    </p>\n\n    <!-- 1. Permit -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">1. The permit, with the contractor pulling it.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      You probably didn't know HVAC requires a building permit. It does &mdash; almost everywhere in the U.S. The <strong>permit</strong> is your local building department's way of saying &ldquo;we'll send an inspector to verify this was installed correctly.&rdquo; Why the contractor (not you) should pull it: a licensed contractor pulls the permit under <em>their</em> license, which makes them legally responsible for passing inspection.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      <strong>Look for:</strong> a &ldquo;permit fee&rdquo; line item (typically $50-$500) AND confirmation that the contractor is the one filing it.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means:</strong> they're either skipping the permit (illegal in most jurisdictions), or pushing the legal responsibility onto you. A few jurisdictions allow homeowner-pulled permits, but ask why they're not handling it themselves &mdash; the answer reveals a lot.\n    </p>\n\n    <!-- 2. Equipment + AHRI -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">2. Specific make, model, and AHRI certificate number.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Not just &ldquo;3-ton Carrier system.&rdquo; Real quotes name the exact <strong>outdoor unit</strong> (the box outside, sometimes called the &ldquo;condenser&rdquo;) AND the exact <strong>indoor unit</strong> (the cabinet in your basement, attic, or closet, sometimes called the &ldquo;air handler&rdquo;), with full model numbers AND an <strong>AHRI certificate number</strong>.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Plain English on AHRI: it stands for the Air-Conditioning, Heating, and Refrigeration Institute &mdash; an independent industry lab that tests pairs of components and certifies their efficiency. &ldquo;AHRI-matched&rdquo; means the indoor and outdoor units have been tested together and confirmed to work at their advertised efficiency. Mismatched pairs (a contractor pairing a new outdoor unit with your old indoor coil to save money) can run 15-20% less efficient than the box says.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      <strong>Look for:</strong> model numbers for both units (a real model number is alphanumeric, usually 8-12 characters &mdash; not a vague description), and a 7-digit AHRI certificate number.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means:</strong> the contractor either doesn't know which exact model they're proposing yet (sloppy), or doesn't want you to look it up (sketchy). A reputable contractor lists this clearly.\n    </p>\n\n    <!-- 3. Refrigerant -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">3. The refrigerant type.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>Refrigerant</strong> is the fluid inside an AC or heat pump that carries heat in or out of your home. It's federally regulated &mdash; handling it requires an EPA 608 certification. Any technician working on your system is supposed to have it.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      <strong>Look for:</strong> the refrigerant type called out by name. R-410A (the old standard) is being phased out under U.S. environmental rules. The replacements are R-32 and R-454B.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means</strong> (or R-410A on a new install): the contractor is either selling old stock &mdash; cheaper for them now, harder for you to repair in 5+ years &mdash; or behind on training. Worth asking why they're not on the newer refrigerants.\n    </p>\n\n    <!-- 4. Ductwork -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">4. Ductwork &mdash; what's included.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>Ducts</strong> are the metal or insulated-fabric tubes that carry heated or cooled air from your HVAC system to each room. They run inside walls, ceilings, attics, and basements &mdash; you usually only see them as the slotted vents on your floors or ceilings (those are called <strong>registers</strong>). If you have central heat or AC, you have ducts.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      <strong>Look for:</strong> explicit mention of new duct runs needed, sealing, insulation upgrades, or repairs to existing ducts.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means:</strong> either no duct work is needed (rare for an existing system), or the contractor is hiding a future &ldquo;we found problems mid-install&rdquo; upsell. Ask explicitly: &ldquo;Did you inspect the existing ductwork? What condition is it in?&rdquo; A contractor who can't answer hasn't actually looked.\n    </p>\n\n    {% if home.sqft >= 3000 %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;background-color:#fff7ed;border-left:3px solid #FF6B2B;padding:12px 16px;\">\n      At your home size ({{ home.sqft | comma }} sqft), this is one of the most common surprise charges. Industry rule of thumb: a duct system needs to move 400 cubic feet of air per minute, per ton of cooling. So your ducts need to handle ~{{ home.tonnage | times: 400 | comma }} cubic feet per minute. If a quote doesn't mention duct-capacity testing, ask whether they verified your existing ducts can handle the new system. The answer should be specific.\n    </p>\n    {% endif %}\n\n    <!-- 5. Warranty -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">5. Warranty terms &mdash; both parts AND labor, separately.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">Two warranties on every install:</p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 12px 24px;padding:0;\">\n      <li style=\"margin-bottom:8px;\"><strong>Parts warranty</strong> comes from the manufacturer. Usually 10 years on major components if you register the unit. Covers the equipment.</li>\n      <li><strong>Labor warranty</strong> comes from the contractor. Usually 1-2 years. Covers their cost to install replacement parts.</li>\n    </ul>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Why both matter: if a $400 part fails and the manufacturer covers it but you have no labor warranty, you're paying $1,500+ in labor to install the free part.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      <strong>Look for:</strong> two separate durations called out &mdash; e.g., &ldquo;10-year parts / 2-year labor.&rdquo;\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means:</strong> either no labor warranty (the contractor doesn't trust their own install), or labor warranty bundled into a vague &ldquo;1-year warranty&rdquo; line you can't compare against another quote. Press for the breakdown.\n    </p>\n\n    <!-- 6. Commissioning -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">6. Commissioning.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      This is the magic word. <strong>Commissioning</strong> is the post-install testing that verifies the system actually performs at its rated efficiency: measuring airflow at every register, checking refrigerant charge, measuring temperature differences, and giving you a written report.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      <strong>Look for:</strong> explicit mention of &ldquo;commissioning&rdquo; or &ldquo;post-install verification with written report.&rdquo;\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means:</strong> most contractors skip commissioning. The ones who do it call it out as a line item. Ask each contractor directly: &ldquo;Do you commission the system after install?&rdquo; The answer separates careful contractors from the rest.\n    </p>\n\n    <!-- 7. Disposal -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">7. Old-system disposal.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      Hauling away the old equipment, reclaiming the old refrigerant. Should be itemized.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      <strong>Look for:</strong> a &ldquo;disposal&rdquo; or &ldquo;removal&rdquo; line item.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means:</strong> a contractor who plans to leave your old AC in the side yard &ldquo;for you to handle&rdquo; is also probably cutting other corners.\n    </p>\n\n    <!-- 8. Electrical -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">8. Electrical work.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      A new HVAC system needs electrical service. The quote should call out the specific pieces:\n    </p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 12px 24px;padding:0;\">\n      <li style=\"margin-bottom:6px;\"><strong>Disconnect</strong> &mdash; a small outdoor switch box mounted next to the unit, used to cut power for service.</li>\n      <li style=\"margin-bottom:6px;\"><strong>Breaker</strong> &mdash; a new switch in your home's electrical panel, sized for the new system's load.</li>\n      <li><strong>Whip</strong> &mdash; a short flexible cable that connects the disconnect to the unit itself.</li>\n    </ul>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      <strong>Look for:</strong> these items mentioned by name, OR a clear note that no electrical work is needed because the existing wiring matches.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means:</strong> either the contractor is sub-ing the electrical work and burying the cost, or they're planning to skip something they shouldn't. If your home was built before 1990, your panel may need upgrading &mdash; that's a separate licensed-electrician line item, not something to hide inside the HVAC bid.\n    </p>\n\n    <!-- 9. Zoning -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">9. Zoning, if applicable.</h3>\n    {% if home.sqft >= 2500 %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      For a {{ home.sqft | comma }} sqft home, this is worth a conversation. <strong>Zoning</strong> means splitting the house into independently-controlled regions, each with its own thermostat. Motorized <strong>dampers</strong> (basically flaps inside the ducts) open and close to direct airflow where it's wanted. Adds $1,000-$3,000 up front, pays back in comfort + bills, especially in multi-story homes (heat rises, upstairs always too hot in summer without zoning).\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means:</strong> if none of your quotes brought up zoning for a home your size, the contractors are either not thinking carefully or just optimizing for cheapest bid. The bid that wins on price won't deliver the most comfort.\n    </p>\n    {% else %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Probably not relevant for your home size, but worth knowing the term: <strong>zoning</strong> means having multiple thermostats and <strong>dampers</strong> (motorized flaps in the ducts) that let you cool different rooms independently. Comes up more in larger or multi-story homes. Skip the score on this one.\n    </p>\n    {% endif %}\n\n    <!-- 10. Labor breakdown -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">10. Labor breakdown, separated from equipment.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      A real quote splits out: equipment cost, materials cost, labor cost, permit fee, disposal fee.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 6px 0;\">\n      <strong>Look for:</strong> a clear line-item breakdown.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <strong>Missing means:</strong> if it's one lump-sum number, you can't compare two quotes meaningfully &mdash; and the contractor knows it. Ask each quote-giver for an itemized breakdown. A contractor who refuses is one whose pricing won't survive the comparison.\n    </p>\n\n    <!-- Climate-specific watch-out -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:32px 0 8px 0;\">One climate-specific watch-out:</h3>\n\n    {% if location.climate_region == \"Cold\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      For your zone (IECC Zone {{ location.iecc_zone }}, {{ location.state }}), check whether each quote sized the system for your <strong>design heating temperature</strong> ({{ location.design_temp_low }}&deg;F &mdash; the coldest you can reasonably expect on a winter day) or for an average winter day. Some contractors size for the average so they can quote a smaller, cheaper system &mdash; and three weeks of every winter, you have a system that can't keep up. Real bids reference design conditions explicitly. (&ldquo;IECC&rdquo; is the International Energy Conservation Code &mdash; it splits the U.S. into climate zones used by the building industry.)\n    </p>\n    {% endif %}\n\n    {% if location.climate_region == \"Hot\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      For your zone (IECC Zone {{ location.iecc_zone }}, {{ location.state }}), check whether each contractor mentions <strong>Manual J</strong> &mdash; the industry-standard load calculation method. If a quote doesn't reference Manual J, or doesn't address humidity at all, that contractor likely oversizes systems and produces clammy, uncomfortable homes. (A system that just lowers the temperature without removing moisture is the difference between feeling cool and feeling cold-and-clammy.) (&ldquo;IECC&rdquo; is the International Energy Conservation Code &mdash; it splits the U.S. into climate zones.)\n    </p>\n    {% endif %}\n\n    {% if location.climate_region == \"Warm\" or location.climate_region == \"Mixed\" or location.climate_region == \"Cool\" %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      For your zone (IECC Zone {{ location.iecc_zone }}), the system has to perform across a wide temperature range. Check whether each quote addresses both your <strong>design heating temperature</strong> ({{ location.design_temp_low }}&deg;F) AND your <strong>design cooling temperature</strong> ({{ location.design_temp_high }}&deg;F). A quote addressing only one is half a quote. (&ldquo;IECC&rdquo; is the International Energy Conservation Code &mdash; it splits the U.S. into climate zones.)\n    </p>\n    {% endif %}\n\n    <h3 style=\"font-size:16px;color:#18181b;margin:32px 0 8px 0;\">How to read your scores:</h3>\n\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\"><strong>9-10 &check;:</strong> serious bidder. Move on to comparing warranty, timeline, and contractor reputation against price (we'll cover the framework on Day 10).</li>\n      <li style=\"margin-bottom:10px;\"><strong>6-8 &check;:</strong> missing pieces. Push back, ask for the missing items in writing. Reputable contractors will revise without complaint. The ones who get defensive are telling you something.</li>\n      <li><strong>5 or fewer &check;:</strong> that's not a quote you can really compare. Either the contractor will provide more detail when pushed (give them one chance), or they're not bringing the level of detail you need.</li>\n    </ul>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      If your existing quotes are scoring on the lower end, the asymmetric move is one more independent bid from a contractor who hits all 10 items. Angi will set that up in 24 hours so you have a clean third comparison.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 28px 0;\">\n      <a href=\"{{ cta_url }}\" style=\"color:#FF6B2B;font-weight:600;text-decoration:underline;\">Get one more quote that hits all 10 &rarr;</a>\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 4px 0;\">&mdash; NailTheQuote</p>\n    <p style=\"font-size:14px;line-height:1.65;margin:0 0 16px 0;color:#71717a;font-style:italic;\">\n      P.S. On Day 3 we'll cover the specific pricing tricks contractors use to make their quote look better than it is &mdash; the brand-substitution play, the labor-only quote that hides equipment markup, the cash-no-permit dodge, and a few more. After that email you'll be reading these quotes like you've worked the trade.\n    </p>\n\n        <hr style=\"border:none;border-top:1px solid #e4e4e7;margin:32px 0 16px 0;\">\n    <p style=\"font-size:12px;color:#a1a1aa;line-height:1.5;margin:0 0 6px 0;\">\n      You're receiving this because you used the <a href=\"https://nailthequote.com/hvac/load-calculator/\" style=\"color:#a1a1aa;\">Load Calculator</a> on NailTheQuote.com. We send 3 emails over 10 days, then stop.\n    </p>\n    <p style=\"font-size:11px;color:#a1a1aa;margin:0;\">\n      NailTheQuote.com &middot; Free tools for homeowners and contractors<br>\n      {% raw %}<a href=\"{{{unsubscribe_url}}}\" style=\"color:#a1a1aa;\">Unsubscribe</a>{% endraw %}\n    </p>\n\n\n  </div>\n</body>\n</html>\n",
  "day3": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>5 pricing tricks HVAC contractors use (and how to spot them)</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#ffffff;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#27272a;\">\n  <div style=\"max-width:600px;margin:0 auto;padding:32px 20px;\">\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">Hey,</p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Three days ago I sent you the 10-item checklist for evaluating your HVAC quotes. Today is the inside-baseball follow-up: the specific pricing tricks contractors use to make their bid look better than it is.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      None of these are illegal. Some are conscious cons; others are just industry habits the contractor isn't trying to hide. They all share one feature: the homeowner doesn't realize what's happening until after they've signed. Here are the five most common, with what to ask each contractor to surface them.\n    </p>\n\n    <!-- Trick 1 -->\n    <h3 style=\"font-size:17px;color:#18181b;margin:28px 0 8px 0;\">Trick #1 &mdash; The brand-substitution play</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>The pattern:</strong> the contractor quotes a known brand on the proposal (Carrier, Trane, Lennox, etc.). On install day, they show up with a different brand or a lower-tier model from the same brand, with the explanation &ldquo;we're out of stock on that one &mdash; this one's equivalent.&rdquo; It usually isn't equivalent. The substitute is usually cheaper for them, while the price you pay stays the same.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>How to spot it:</strong> the quote names a brand and a tonnage but the model number is vague or missing. &ldquo;Carrier 16 SEER 3-ton&rdquo; is not a model. A real model number is alphanumeric and 8-12 characters long &mdash; like &ldquo;24ABB7&rdquo; or &ldquo;CSA624GKA.&rdquo; Vague description = wiggle room.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 8px 0;\"><strong>How to counter:</strong></p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\">Demand the full alphanumeric model number for both indoor and outdoor units on the written contract &mdash; and the AHRI certificate number (7 digits, looks like &ldquo;12345678&rdquo;). Cross-check it on ahridirectory.org before you sign. If they won't put a model number in writing, they don't actually know what they're installing.</li>\n      <li style=\"margin-bottom:10px;\">Add a substitution clause: &ldquo;Any equipment substitution requires written notice 48 hours before install, with proof of equivalent AHRI certificate. Buyer reserves the right to cancel without penalty if the substitute differs in tonnage, SEER2/HSPF2, or refrigerant type.&rdquo; A real contractor signs this without flinching.</li>\n      <li>On install day, before final payment, walk outside with the invoice and check the model number on the unit nameplate (usually a metal sticker on the side of the outdoor unit) against the contract. Two minutes of work; saves you the substitution every time.</li>\n    </ul>\n\n    <!-- Trick 2 -->\n    <h3 style=\"font-size:17px;color:#18181b;margin:28px 0 8px 0;\">Trick #2 &mdash; The labor-only quote (with hidden equipment markup)</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>The pattern:</strong> the contractor quotes labor at a low number, then orders equipment with significant markup over what you could buy it for at retail. The bottom-line price looks competitive, but you're overpaying on the equipment side. Counts on the homeowner not knowing what HVAC equipment actually costs.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>How to spot it:</strong> the quote shows labor and equipment as separate numbers, but the equipment line is significantly above retail. Some markup over retail is normal &mdash; the contractor handles ordering, delivery, returns, warranty registration. But the markup should be in the 15-25% range, not 60%.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 8px 0;\"><strong>How to counter:</strong></p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\">Spot-check the equipment cost on supplyhouse.com or HVACDirect. You don't need to price the whole job &mdash; pick the outdoor unit by model number and look up the wholesale price. Contractor markup of 15-25% over wholesale is normal; 50%+ is the trick.</li>\n      <li style=\"margin-bottom:10px;\">Ask each contractor: &ldquo;Can you give me your hourly labor rate and the marked-up equipment subtotal as separate line items?&rdquo; The honest ones answer in one sentence. The trickier ones say &ldquo;we don't itemize that way&rdquo; &mdash; that itself is the answer.</li>\n      <li>If two of your quotes have similar labor numbers but the equipment lines diverge by more than 20%, the higher-priced one is almost certainly running this play. Bring the wholesale price to the conversation: &ldquo;I see this unit retails for $X at SupplyHouse. Can you walk me through the markup?&rdquo;</li>\n    </ul>\n\n    <!-- Trick 3 -->\n    <h3 style=\"font-size:17px;color:#18181b;margin:28px 0 8px 0;\">Trick #3 &mdash; The &ldquo;permit-by-homeowner&rdquo; dodge</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>The pattern:</strong> the contractor asks you to pull the permit. This shifts legal responsibility from the contractor to you. Sometimes there's a real reason (some jurisdictions allow owner-builder permits and the homeowner prefers it). More often it's a sign the contractor doesn't have the right license, isn't insured, or is trying to avoid the inspection paperwork.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>How to spot it:</strong> any quote where you're listed as the permit-puller, OR where the permit &ldquo;is included on your part&rdquo; or &ldquo;will be handled by the homeowner.&rdquo;\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 8px 0;\"><strong>How to counter:</strong></p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\">Refuse politely but firmly: &ldquo;I'd prefer my licensed contractor pull the permit, since you're the one doing the work.&rdquo; A legitimate contractor agrees in 10 seconds. One who pushes back is telling you why they don't want to.</li>\n      <li style=\"margin-bottom:10px;\">If they push back with &ldquo;it's faster this way&rdquo; or &ldquo;saves you a fee&rdquo; &mdash; those aren't reasons, they're hand-waves. Ask directly: &ldquo;Are you licensed for HVAC in this jurisdiction? What's your license number?&rdquo; Then verify it yourself.</li>\n      <li>Look up the license online (every state has a free contractor license lookup &mdash; search &ldquo;[your state] contractor license search&rdquo;). Confirm: HVAC scope, current insurance on file, no open disciplinary actions. If the license doesn't check out, the cheapest install on your shortlist is no install at all.</li>\n    </ul>\n\n    <!-- Trick 4 -->\n    <h3 style=\"font-size:17px;color:#18181b;margin:28px 0 8px 0;\">Trick #4 &mdash; Under-scoped ductwork</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>The pattern:</strong> the quote is silent on ductwork. Mid-install, the contractor &ldquo;discovers&rdquo; issues &mdash; sealing, replacement runs, insulation upgrades &mdash; and adds $2-5K to the bill. By then you can't switch contractors without losing the partial install.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>How to spot it:</strong> the quote doesn't mention ductwork at all, or vaguely says &ldquo;ductwork as needed&rdquo; without specifying what was inspected.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 8px 0;\"><strong>How to counter:</strong></p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\">Get the duct inspection in writing &mdash; email, not verbal. Ask: &ldquo;Did you physically inspect the existing ductwork during the site visit? What's the condition? What duct work is in this quote, and what is explicitly excluded?&rdquo; A contractor who inspected can answer in three sentences. One who didn't will deflect.</li>\n      <li style=\"margin-bottom:10px;\">Strike out any &ldquo;ductwork as needed&rdquo; line and replace it with itemized scope: &ldquo;Existing ducts inspected on [date]; condition: [acceptable / X linear feet of replacement needed / Y joints to be sealed]. Additional duct work, if discovered during install, charged at $X/linear foot or $Y/joint, requiring written approval.&rdquo;</li>\n      <li>Add a contract clause capping mid-install change orders at 10% of the bid total without written approval, with your right to halt work if you disagree with the new scope. The contractor who refuses this clause is the one planning to use it against you.</li>\n    </ul>\n\n    {% if home.sqft >= 3000 %}\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;background-color:#fff7ed;border-left:3px solid #FF6B2B;padding:12px 16px;\">\n      At your home size ({{ home.sqft | comma }} sqft), this is one of the most common surprise charges. The clauses above are non-negotiable for a home this size.\n    </p>\n    {% endif %}\n\n    <!-- Trick 5 -->\n    <h3 style=\"font-size:17px;color:#18181b;margin:28px 0 8px 0;\">Trick #5 &mdash; The &ldquo;we'll just do it in cash&rdquo; dodge</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>The pattern:</strong> the contractor offers a discount for cash payment, no contract, no permit. You save 10-15% on the headline number. They save much more &mdash; no taxes paid, no permit fees, no warranty obligations, no liability if something goes wrong.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      <strong>How to spot it:</strong> any cash discount that comes with &ldquo;we don't need to write everything down&rdquo; energy.\n    </p>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 8px 0;\"><strong>How to counter:</strong></p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 24px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\">Pay however you want, but always sign a written contract &mdash; with the brand, model, AHRI number, scope, warranty terms, and price. If the cash discount comes paired with &ldquo;we don't need to write this down,&rdquo; walk away. The contract is the warranty; without it, you have no warranty regardless of what they promised.</li>\n      <li style=\"margin-bottom:10px;\">Always require the permit to be pulled. The discount evaporates the first time something goes wrong &mdash; your homeowner's insurance can deny claims for unpermitted work, and so can your buyer's inspector when you sell the house in 5 years.</li>\n      <li>If the cash discount is more than ~5%, the contractor isn't just dodging sales tax &mdash; they're likely uninsured for the install crew. If a tech falls off your roof, that's now your liability. Ask for proof of workers' comp + general liability insurance, in writing, with your address listed as the work site. A real contractor's insurer can issue a certificate same-day.</li>\n    </ul>\n\n    <h3 style=\"font-size:17px;color:#18181b;margin:32px 0 8px 0;\">If you spot any of these on your current quotes:</h3>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      The asymmetric move is getting one more independent bid. Honest contractors don't run these patterns. So if Quote A has the brand-substitution risk, Quote B has the labor-only structure, and you're trying to decide between them &mdash; you're choosing between two flavors of risk. A third bid from a contractor who passes the 10-item Day 0 checklist gives you a baseline you can actually trust.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      <a href=\"{{ cta_url }}\" style=\"color:#FF6B2B;font-weight:600;text-decoration:underline;\">Get one more independent quote &rarr;</a>\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      It takes 24 hours. If your existing quotes are clean, you've spent one phone call and learned that. If they're not, you've just saved yourself a problem.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 4px 0;\">&mdash; NailTheQuote</p>\n    <p style=\"font-size:14px;line-height:1.65;margin:0 0 16px 0;color:#71717a;font-style:italic;\">\n      P.S. On Day 10 &mdash; the final email &mdash; we'll cover how to actually choose between quotes once the bad ones are filtered out. The decision framework, the tiebreaker, and what to do when two quotes are within 5% on price.\n    </p>\n\n        <hr style=\"border:none;border-top:1px solid #e4e4e7;margin:32px 0 16px 0;\">\n    <p style=\"font-size:12px;color:#a1a1aa;line-height:1.5;margin:0 0 6px 0;\">\n      You're receiving this because you used the <a href=\"https://nailthequote.com/hvac/load-calculator/\" style=\"color:#a1a1aa;\">Load Calculator</a> on NailTheQuote.com. We send 3 emails over 10 days, then stop.\n    </p>\n    <p style=\"font-size:11px;color:#a1a1aa;margin:0;\">\n      NailTheQuote.com &middot; Free tools for homeowners and contractors<br>\n      {% raw %}<a href=\"{{{unsubscribe_url}}}\" style=\"color:#a1a1aa;\">Unsubscribe</a>{% endraw %}\n    </p>\n\n\n  </div>\n</body>\n</html>\n",
  "day10": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>How to actually pick between HVAC quotes</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#ffffff;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#27272a;\">\n  <div style=\"max-width:600px;margin:0 auto;padding:32px 20px;\">\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">Hey,</p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      You've now had 10 days with your HVAC quotes. Day 0: how to score them. Day 3: the pricing tricks to spot. Today: the actual decision.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      If you've done the work, your quotes have been filtered. Either you're left with 2-3 clean ones that hit the 10-item checklist and don't show any of the pricing tricks, OR one of your originals dropped out (it was the brand-swap one, or the cash-deal one, or the missing-permit one). Either way, the next move is choosing.\n    </p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Here's the framework. Score each remaining quote on five dimensions, then use the scores to decide. The tiebreaker, when scores are within 5%: <em>don't pick on price.</em>\n    </p>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">The five dimensions:</h2>\n\n    <!-- Dimension 1 -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">1. Price.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Total bottom-line, including permit, equipment, labor, disposal. Use the cheapest as your baseline (call it 1.00x), and compute how much more expensive each other quote is. If the cheapest is $12,000 and another is $13,500, the second is 1.125x &mdash; 12.5% more expensive.\n    </p>\n\n    <!-- Dimension 2 -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">2. Warranty.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      Both <strong>parts AND labor warranties, separately.</strong> The standard baseline is 10 years parts / 2 years labor. A 12/5 quote (12-year parts, 5-year labor) is meaningfully better. A 10/1 or 10/0 is meaningfully worse &mdash; labor warranty is the one that costs you real money if something fails.\n    </p>\n\n    <!-- Dimension 3 -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">3. Contractor reputation.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      Three places to check, in rough order of usefulness:\n    </p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\"><strong>State contractor license lookup</strong> (free, definitive). Confirms the license is current, scope covers HVAC, insurance is on file, and surfaces any disciplinary actions or formal complaints. Search &ldquo;[your state] contractor license search&rdquo; &mdash; every state has one. This is the source that actually has consequences attached to it.</li>\n      <li style=\"margin-bottom:10px;\"><strong>BBB</strong> (bbb.org). Useful for spotting <em>patterns</em> of unresolved complaints, not as a single letter-grade verdict (the grade is partly pay-for-play). Look at: total complaint count for a contractor of this size, percentage marked resolved, and whether the contractor responded at all. Five resolved complaints is fine; two unresolved-and-unanswered is a signal.</li>\n      <li><strong>Google reviews and hyper-local platforms</strong> (Nextdoor, neighborhood Facebook groups). Noisier than the first two but catches recent issues the BBB misses by months. Filter for reviews from your ZIP code or surrounding ZIPs if possible &mdash; an installer who's beloved across town can still be terrible at your specific build type.</li>\n    </ul>\n\n    <!-- Dimension 4 -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">4. Timeline.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      When can they install, and how long does the install take? A contractor who can do it next week may be available because they're not in demand. A contractor who's a month out is often busy because they're good. Not always &mdash; but it's a directional signal worth weighing.\n    </p>\n\n    <!-- Dimension 5 -->\n    <h3 style=\"font-size:16px;color:#18181b;margin:24px 0 8px 0;\">5. What's included.</h3>\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      From the Day 0 checklist: did they include commissioning? Old-system disposal? Electrical work? Full ductwork? Each &ldquo;yes&rdquo; is included scope. The cheapest quote isn't a bargain if it's missing $2,000 worth of scope the other quotes include.\n    </p>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">A worked example:</h2>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">Three quotes from the same evaluation:</p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:8px;\"><strong>Quote A:</strong> $11,500. 10-year parts / 1-year labor. Mixed BBB record. Available next week. Missing commissioning and disposal line items.</li>\n      <li style=\"margin-bottom:8px;\"><strong>Quote B:</strong> $13,200. 10-year parts / 5-year labor. A+ BBB, no complaints. 3 weeks out. Includes everything.</li>\n      <li><strong>Quote C:</strong> $12,400. 10-year parts / 2-year labor. Solid BBB, one resolved complaint. 2 weeks out. Includes everything except commissioning.</li>\n    </ul>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 12px 0;\">\n      On price alone, A wins by $1,700 over C and $1,900 over B. But:\n    </p>\n    <ul style=\"font-size:15px;line-height:1.7;margin:0 0 16px 24px;padding:0;\">\n      <li style=\"margin-bottom:10px;\"><strong>Quote A is missing scope, not winning on price.</strong> No commissioning (~$300 if added later), no old-system disposal (~$200), and a 1-year labor warranty vs. the others' 2-5. True apples-to-apples cost is closer to $13,000 once you backfill the missing items &mdash; barely cheaper than C, more expensive than B once warranty value is priced in.</li>\n      <li style=\"margin-bottom:10px;\"><strong>Quote B's 5-year labor warranty is worth ~$2,000 in expected value.</strong> The compressor or heat exchanger failing in years 3-5 is the most common expensive failure mode. Quote A leaves you holding $1,500-2,500 in labor for that repair; Quote B covers it. That gap alone closes the $1,700 price difference between A and B.</li>\n      <li><strong>Quote B being 3 weeks out tells you something good.</strong> Contractors with 2-3 week wait lists are usually busy because they're good. Quote A's &ldquo;available next week&rdquo; sometimes means new in business &mdash; but in established markets it more often means slack capacity from lost customers. Not a hard rule, but a directional tiebreaker that points the same direction as the warranty math.</li>\n    </ul>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      The right answer here is <strong>B</strong> &mdash; even though it's the most expensive on paper. The 5-year labor warranty alone is worth roughly $2,000 in expected service costs over the system's lifetime.\n    </p>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">The tiebreaker:</h2>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 24px 0;\">\n      When two quotes are within 5% on price (so within ~$600 on a $12,000 install), <strong>don't pick on price.</strong> Pick on warranty + timeline + reputation. The price difference will round to nothing over a 15-year system lifespan; the warranty + reputation difference compounds.\n    </p>\n\n    <h2 style=\"font-size:17px;color:#18181b;margin:32px 0 12px 0;\">The &ldquo;still unsure&rdquo; play:</h2>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">\n      If you're still genuinely torn between two quotes &mdash; or if all your quotes are missing pieces that would make the decision clean &mdash; the asymmetric move is one more independent bid from a contractor who hits all 10 items on the Day 0 checklist. Takes 24 hours. Cost is one phone call. The upside is either confirmation that your existing favorite is the right call, or a third option that's better than both.\n    </p>\n\n    <div style=\"margin:0 0 24px 0;text-align:center;\">\n      <a href=\"{{ cta_url }}\" style=\"display:inline-block;background:#FF6B2B;color:#ffffff;font-size:15px;font-weight:600;text-decoration:none;padding:14px 28px;border-radius:8px;\">\n        Get one more independent bid &rarr;\n      </a>\n    </div>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 16px 0;\">Good luck with the decision.</p>\n\n    <p style=\"font-size:15px;line-height:1.65;margin:0 0 4px 0;\">&mdash; NailTheQuote</p>\n    <p style=\"font-size:14px;line-height:1.65;margin:0 0 16px 0;color:#71717a;font-style:italic;\">\n      P.S. Once you've signed: keep every email, certificate, model number, and AHRI number from the install. If your install is a heat pump, ask the contractor for the manufacturer's certification statement &mdash; you'll need it to claim the IRA Section 25C federal tax credit (worth up to $2,000 against your federal taxes). And for any warranty claim down the line, the paperwork is what makes the difference between &ldquo;covered&rdquo; and &ldquo;good luck.&rdquo;\n    </p>\n\n        <hr style=\"border:none;border-top:1px solid #e4e4e7;margin:32px 0 16px 0;\">\n    <p style=\"font-size:12px;color:#a1a1aa;line-height:1.5;margin:0 0 6px 0;\">\n      You're receiving this because you used the <a href=\"https://nailthequote.com/hvac/load-calculator/\" style=\"color:#a1a1aa;\">Load Calculator</a> on NailTheQuote.com. We send 3 emails over 10 days, then stop.\n    </p>\n    <p style=\"font-size:11px;color:#a1a1aa;margin:0;\">\n      NailTheQuote.com &middot; Free tools for homeowners and contractors<br>\n      {% raw %}<a href=\"{{{unsubscribe_url}}}\" style=\"color:#a1a1aa;\">Unsubscribe</a>{% endraw %}\n    </p>\n\n\n  </div>\n</body>\n</html>\n",
};

export const PERSONA2_FOOTER_PARTIAL: string = "    <hr style=\"border:none;border-top:1px solid #e4e4e7;margin:32px 0 16px 0;\">\n    <p style=\"font-size:12px;color:#a1a1aa;line-height:1.5;margin:0 0 6px 0;\">\n      You're receiving this because you used the <a href=\"https://nailthequote.com/hvac/load-calculator/\" style=\"color:#a1a1aa;\">Load Calculator</a> on NailTheQuote.com. We send 3 emails over 10 days, then stop.\n    </p>\n    <p style=\"font-size:11px;color:#a1a1aa;margin:0;\">\n      NailTheQuote.com &middot; Free tools for homeowners and contractors<br>\n      {% raw %}<a href=\"{{{unsubscribe_url}}}\" style=\"color:#a1a1aa;\">Unsubscribe</a>{% endraw %}\n    </p>\n";

// email_number → template key. Indexes match PERSONA2_MANIFEST.sequence order.
export const PERSONA2_TEMPLATE_BY_NUMBER = ["day0", "day3", "day10"] as const;
export type Persona2TemplateKey = (typeof PERSONA2_TEMPLATE_BY_NUMBER)[number];
